/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Exports the contents of a grid (using the selected order and filters) to an Excel file. LoadWWPContext.Call(&Context)
Do 'OpenDocument'
&CellRow = 1 &FirstColumn = 1
Do 'LoadGridState'
Do 'WriteFilters'
Do 'WriteColumnTitles'
Do 'WriteData'
Do 'CloseDocument'
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
Sub 'OpenDocument'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&Random = Random() * 10000 &Filename = !"ExportWWVendedorComissao-" + &Random.ToString().Trim() + !".xlsx"
&ExcelDocument.Open(&Filename) Do 'CheckStatus' &ExcelDocument.Clear()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteFilters'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If not (&PesSts.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Status") If Not &PesSts.IsEmpty() &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = &PesSts.EnumerationDescription() Endif EndIf
If not (&PesCod.IsEmpty() AND &PesRaz.IsEmpty() AND &IncluirDemitidos.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Código") &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &PesCod &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = WWP_Export_SecureText(&PesRaz) WWP_ExportWriteFilter(&ExcelDocument, false, &CellRow, &FirstColumn + 3, "Status") &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Text = '' do Case Case &IncluirDemitidos.ToString().Trim() = "S" &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Text = "Incluir Demitidos"
Case &IncluirDemitidos.ToString().Trim() = "N" &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Text = " Vendedores Vigêntes"
EndCase EndIf
If not (&PesComUltLct.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Ult Lct") &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &PesComUltLct EndIf &CellRow += 2
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteColumnTitles'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Text = "Código" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = "Nome Comissionado" &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = "Status" &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Text = "Vend." &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Text = "Func." &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Text = "UF" &ExcelDocument.Cells(&CellRow, &FirstColumn + 6).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 6).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 6).Text = "Cidade" &ExcelDocument.Cells(&CellRow, &FirstColumn + 7).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 7).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 7).Text = "Área" &ExcelDocument.Cells(&CellRow, &FirstColumn + 8).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 8).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 8).Text = "Nome Área"
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteData'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
For each order EmpCod PesRaz when &OrderedBy = 1 order PesCod when &OrderedBy = 2 AND &OrderedDsc = False order (PesCod) when &OrderedBy = 2 AND &OrderedDsc = True order PesRaz when &OrderedBy = 3 AND &OrderedDsc = False order (PesRaz) when &OrderedBy = 3 AND &OrderedDsc = True order PesSts when &OrderedBy = 4 AND &OrderedDsc = False order (PesSts) when &OrderedBy = 4 AND &OrderedDsc = True order PesIsVen when &OrderedBy = 5 AND &OrderedDsc = False order (PesIsVen) when &OrderedBy = 5 AND &OrderedDsc = True order PesIsFun when &OrderedBy = 6 AND &OrderedDsc = False order (PesIsFun) when &OrderedBy = 6 AND &OrderedDsc = True order PesCidUfeCod when &OrderedBy = 7 AND &OrderedDsc = False order (PesCidUfeCod) when &OrderedBy = 7 AND &OrderedDsc = True order PesCidNom when &OrderedBy = 8 AND &OrderedDsc = False order (PesCidNom) when &OrderedBy = 8 AND &OrderedDsc = True order PesVenAreCod when &OrderedBy = 9 AND &OrderedDsc = False order (PesVenAreCod) when &OrderedBy = 9 AND &OrderedDsc = True order PesVenAreNom when &OrderedBy = 10 AND &OrderedDsc = False order (PesVenAreNom) when &OrderedBy = 10 AND &OrderedDsc = True
using DSWWVendedorComissao(&PesSts, &PesCod, &PesRaz, &IncluirDemitidos, &PesComUltLct)
// Write cell values &CellRow += 1
Do 'BeforeWriteLine' &ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Number = PesCod &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(PesRaz) &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = PesSts.EnumerationDescription() &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Text = PesIsVen.ToString() &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Text = PesIsFun.ToString() &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Text = WWP_Export_SecureText(PesCidUfeCod) &ExcelDocument.Cells(&CellRow, &FirstColumn + 6).Text = WWP_Export_SecureText(PesCidNom) &ExcelDocument.Cells(&CellRow, &FirstColumn + 7).Number = PesVenAreCod &ExcelDocument.Cells(&CellRow, &FirstColumn + 8).Text = WWP_Export_SecureText(PesVenAreNom)
Do 'AfterWriteLine'
Endfor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'CloseDocument'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&ExcelDocument.Save() Do 'CheckStatus' &ExcelDocument.Close()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'CheckStatus'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If (&ExcelDocument.ErrCode <> 0) &Filename = "" &ErrorMessage = &ExcelDocument.ErrDescription &ExcelDocument.Close() Return EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'LoadGridState'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Load grid state from session. If &Session.Get(!"WWVendedorComissaoGridState") = !"" &GridState.FromXml(LoadGridState.Udp(!"WWVendedorComissaoGridState")) Else &GridState.FromXml(&Session.Get(!"WWVendedorComissaoGridState")) Endif
&OrderedBy = &GridState.OrderedBy &OrderedDsc = &GridState.OrderedDsc
For &GridStateFilterValue in &GridState.FilterValues Do Case Case &GridStateFilterValue.Name = !"PESSTS" &PesSts.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PESCOD" &PesCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PESRAZ" &PesRaz.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"INCLUIRDEMITIDOS" &IncluirDemitidos.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PESCOMULTLCT" &PesComUltLct.FromString(&GridStateFilterValue.Value) EndCase EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'BeforeWriteLine'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'AfterWriteLine'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub

	/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */

parm(out:&Filename, out:&ErrorMessage);

	/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
